import{_ as a}from"./audio-player.2439fc59.js";import{e as s,f as r,g as n,D as e}from"./framework.16919e8f.js";const t='{"title":"Панчабрахма мантра","description":"","frontmatter":{"title":"Панчабрахма мантра","subtitle":"Мантра пяти брахм — пяти олицетворений Шивы, отвечающих за создание, поддержание, разрушение Вселенной, а также сокрытие и раскрытие своей истинной природы в ней.","sans":"पञ्चब्रह्मा मन्त्र","trans":"pañcabrahmā mantra","tags":"mantra","date":"2021-04-30T00:00:00.000Z"},"headers":[{"level":3,"title":"Садйоджата — Перворождённый — творение","slug":"садйоджата-—-перворождённый-—-творение"},{"level":3,"title":"Вамадева — Прекрасный бог — поддержание","slug":"вамадева-—-прекрасный-бог-—-поддержание"},{"level":3,"title":"Агхора — Бесстрашный — разрушение","slug":"агхора-—-бесстрашный-—-разрушение"},{"level":3,"title":"Татпуруша — Высшее существо — самосокрытие, скрытая милость","slug":"татпуруша-—-высшее-существо-—-самосокрытие-скрытая-миnость"},{"level":3,"title":"Ишана — Владыка — самораскрытие, проявленная милость","slug":"ишана-—-вnадыка-—-самораскрытие-проявnенная-миnость"},{"level":3,"title":"Шива намаскаратха мантра","slug":"шива-намаскаратха-мантра"},{"level":3,"title":"Вишварупа мантра","slug":"вишварупа-мантра"},{"level":3,"title":"Рудра мантра","slug":"рудра-мантра"}],"relativePath":"mantra/panchabrahma/index.md","lastUpdated":1625159513332}',p={},h=e('<div class="stanza"><p class="sans big">सद्योजात</p><p class="trans">sadyojāta</p><h3 id="садйоджата-—-перворождённый-—-творение"><a class="header-anchor" href="#садйоджата-—-перворождённый-—-творение" aria-hidden="true">#</a> Садйоджата — Перворождённый — творение</h3><p class="sans">ॐ सद्योजातं प्रपद्यामि सद्योजाताय वै नमो नमः ।<br> भवे भवे नाति भवे भवस्व मां भवोद्भवाय नमः ॥</p><p class="trans">оṃ sadyojātaṁ prapadyāmi sadyojātāya vai namo namaḥ<br> bhave bhave nāti bhave bhavasva māṁ bhavodbhavāya namaḥ</p><p>Ищу прибежище в Перворожденном, почитаю Изначальную Причину рождений;<br> Не дай мне рождаться снова и снова; направь меня по ту сторону рождений.</p></div><div class="stanza"><p class="sans big">वामदेवा</p><p class="trans">vāmadeva</p><h3 id="вамадева-—-прекрасный-бог-—-поддержание"><a class="header-anchor" href="#вамадева-—-прекрасный-бог-—-поддержание" aria-hidden="true">#</a> Вамадева — Прекрасный бог — поддержание</h3><p class="sans">ॐ वामदेवायनमो ज्येष्ठाय नमः श्रेष्ठाय नमो रुद्राय नमः कालाय नमः ।<br> कलविकरणाय नमो बलाय नमो बलविकरणाय नमो बलप्रमथनाय नमः ।<br> सर्वभूतदमनाय नमो मनोन्मनाय नमः ॥</p><p class="trans">oṃ vāmadevāya namo jyeṣṭhāya namaḥ śreṣṭhāya namo rudrāya namaḥ kālāya namaḥ<br> kalavikaraṇāya namo balāya namo balavikaraṇāya namo balapramathanāya namaḥ sarvabhūtadamanāya namo manonmanāya namaḥ</p><p>Великодушнейшему поклонение, Старейшему поклонение, Наилучшему поклонение, Рудре поклонение, Времени поклонение;<br> Непостижимейшему поклонение, Величайшей силе поклонение, Причине сил поклонение, Дарующему силы поклонение; Владыке существ поклонение, Источнику света поклонение.</p></div><div class="stanza"><p class="sans big">अघोर</p><p class="trans">aghora</p><h3 id="агхора-—-бесстрашный-—-разрушение"><a class="header-anchor" href="#агхора-—-бесстрашный-—-разрушение" aria-hidden="true">#</a> Агхора — Бесстрашный — разрушение</h3><p class="sans">ॐ अघोरेभ्योऽथ घोरेभ्यो अघोरघोरेतरेभ्यः ।<br> सर्वतः शर्वः सर्वेभ्यो नमस्ते रुद्र रूपेभ्यः ॥</p><p class="trans">oṃ aghorebhyo’tha ghorebhyo aghoraghoretarebhyaḥ<br> sarvataḥ śarvaḥ sarvebhyo namaste rudra rūpebhyaḥ</p><p>Поклонение Неужасному и ужасному, Тому, кто ужасающий и неужасающий одновременно.<br> Всегда и везде, о Шарва, почитаю Рудру во всех его формах.</p></div><div class="stanza"><p class="sans big">तत्पुरुषा</p><p class="trans">tatpuruṣa</p><h3 id="татпуруша-—-высшее-существо-—-самосокрытие-скрытая-миnость"><a class="header-anchor" href="#татпуруша-—-высшее-существо-—-самосокрытие-скрытая-миnость" aria-hidden="true">#</a> Татпуруша — Высшее существо — самосокрытие, скрытая милость</h3><p class="sans">ॐ तत्पुरुषाय विद्महे महादेवाय धीमहि ।<br> तन्नो रुद्रः प्रचोदयात् ॥</p><p class="trans">oṃ tatpuruṣāya vidmahe mahādevāya dhīmahi tanno rudraḥ pracodayāt</p><p>Познаем Высочайшего, будем медитировать на Величайшего -<br> Пусть приведет нас Рудра к просветлению.</p></div><div class="stanza"><p class="sans big">ईशान</p><p class="trans">īsāna</p><h3 id="ишана-—-вnадыка-—-самораскрытие-проявnенная-миnость"><a class="header-anchor" href="#ишана-—-вnадыка-—-самораскрытие-проявnенная-миnость" aria-hidden="true">#</a> Ишана — Владыка — самораскрытие, проявленная милость</h3><p class="sans">ॐ ईशान सर्वविद्यानामीश्वरः सर्वभूतानां ब्रह्मादिपति ब्रह्मणोऽधिपतिर् ।<br> ब्रह्मा शिवो मे अस्तु स एव सदाशिव ओम् ॥</p><p class="trans">oṃ īśāna sarvavidyānāmīśvaraḥ sarvabhūtānāṁ<br> brahmādipati brahmaṇo’dhipatir ।<br> brahmā śivo me astu sa eva sadāśiva om ॥</p><p>Владыка знания и Господь всех существ, Цель всех учений и служений.<br> Он — истинное благо! Да пребудет со мной это Благо вовек!</p></div><div class="stanza"><h3 id="шива-намаскаратха-мантра"><a class="header-anchor" href="#шива-намаскаратха-мантра" aria-hidden="true">#</a> Шива намаскаратха мантра</h3><p class="sans">नमो हिरण्यबाहवे हिरण्यवर्णाय हिरण्यरूपाय हिरण्यपतये ।<br> अम्बिकापतय उमापतये पशुपतये नमो नमः ॥</p><p class="trans">namo hiraṇyabāhave hiraṇyavarṇāya hiraṇyarūpāya hiraṇyapataye ।<br> ambikāpataya umāpataye paśupataye namo namaḥ ॥</p><p>Ом. Склоняю голову и почитаю всем сердцем Божественную Сущность, Вечной Природы, Бессмертной формы, Вечный Господь, Господин Парвати и Умы, Повелитель диких животных [Природы], я предоставляю себя тебе.</p></div><div class="stanza"><h3 id="вишварупа-мантра"><a class="header-anchor" href="#вишварупа-мантра" aria-hidden="true">#</a> Вишварупа мантра</h3><p class="sans">ऋतँ सत्यं परं ब्रह्म पुरुषं कृष्णपिङ्गलम् ।<br> ऊर्ध्वरेतं विरूपाक्षं विश्वरूपाय वै नमो नमः ॥</p><p class="trans">ṛtam̐ satyaṃ paraṃ brahma puruṣaṃ kṛṣṇapiṅgalam ।<br> ūrdhvaretaṃ virūpākśaṃ viśvarūpāya vai namo namaḥ ॥</p><p>Порядок вещей, Истину, Высший Брахман, Божественный дух, Черножёлтого,<br> Восходящее движение энергии, Видящего бесформенное, Имеющего форму Вселенной почитаю и поклоняюсь.</p></div><div class="stanza"><h3 id="рудра-мантра"><a class="header-anchor" href="#рудра-мантра" aria-hidden="true">#</a> Рудра мантра</h3><p class="sans">सर्वो वै रुद्रस्तस्मै रुद्राय नमो अस्तु ।<br> पुरुषो वै रुद्रः सन्महो नमो नमः ।<br> विश्वं भूतं भुवनं चित्रं बहुधा जातं जायमानं च यत् ।<br> सर्वो ह्येष रुद्रस्तस्मै रुद्राय नमो अस्तु ॥</p><p class="trans">arvo vai rudrastasmai rudrāya namo astu ।<br> puruṣo vai rudraḥ sanmaho namo namaḥ ।<br> viśvaṃ bhūtaṃ bhuvanaṃ citraṃ bahudhā jātaṃ jāyamānaṃ ca yat ।<br> sarvo hyeṣa rudrastasmai rudrāya namo astu ॥</p><p class="sans">कद्रुद्राय प्रचेतसे मीढुष्टमाय तव्यसे ।<br> वोचेम शंतमँ हृदे ।<br> सर्वोह्येष रुद्रस्तस्मै रुद्राय नमो अस्तु ॥</p><p class="trans">kadrudrāya pracetase mīḍhuṣṭamāya tavyase ।<br> vocema śaṃtamam̐ hṛde ।<br> sarvohyeṣa rudrastasmai rudrāya namo astu ॥</p></div>',8);p.render=function(e,t,p,i,l,d){const m=a;return s(),r("div",null,[h,n(m,{title:"Uma Mohan",file:"/audio/mohan.mp3"})])};export default p;export{t as __pageData};
